mapper.select:
SELECT m.message_id, m.room_id, m.sender_id, m.message_type, m.content, m.file_url, m.file_name, m.file_size, m.reply_to_id, m.is_recalled, m.recalled_at, m.create_time, m.update_time, r.room_name, r.owner_id, u.nickname AS sender_nickname, reply.content AS reply_to_content, reply_user.nickname AS reply_to_sender_nickname FROM message m LEFT JOIN room r ON m.room_id = r.room_id LEFT JOIN user u ON m.sender_id = u.user_id LEFT JOIN message reply ON m.reply_to_id = reply.message_id LEFT JOIN user reply_user ON reply.sender_id = reply_user.user_id
AND m.room_id = #{query.roomId}
AND m.sender_id = #{query.senderId}
AND r.owner_id = #{query.ownerId}
AND m.message_type = #{query.messageType}
AND m.is_recalled = #{query.isRecalled}
AND m.create_time >= #{query.startTime}
AND m.create_time <= #{query.endTime}
AND m.content LIKE CONCAT('%', #{query.keyword}, '%')
ORDER BY m.create_time DESC
